1	<?php
2	
3	declare(strict_types=1);
4	
5	namespace App\Security;
6	
7	use App\Repository\UserRepository;
8	use Symfony\Component\HttpFoundation\JsonResponse;
9	use Symfony\Component\HttpFoundation\Request;
10	use Symfony\Component\HttpFoundation\Response;
11	use Symfony\Component\Security\Core\Authentication\Token\TokenInterface;
12	use Symfony\Component\Security\Core\Exception\AuthenticationException;
13	use Symfony\Component\Security\Http\Authenticator\AbstractAuthenticator;
14	use Symfony\Component\Security\Http\Authenticator\Passport\Badge\UserBadge;
15	use Symfony\Component\Security\Http\Authenticator\Passport\Passport;
16	use Symfony\Component\Security\Http\Authenticator\Passport\SelfValidatingPassport;
17	
18	/**
19	 * Single-path framework-level authenticator for the API firewall.
20	 *
21	 * Runs for all /api/ routes except PUBLIC_ROUTES. Delegates JWT parsing to
22	 * JwtTokenManager and user lookup to UserRepository. On success, sets the
23	 * authenticated_user request attribute that controllers consume.
24	 */
25	class ApiTokenAuthenticator extends AbstractAuthenticator
26	{
27	    private const PUBLIC_ROUTES = [
28	        '/api/v1/health',
29	        '/api/v1/bootstrap',
30	        '/api/v1/auth/login',
31	        '/api/v1/auth/refresh',
32	        '/api/v1/payments/callback',
33	    ];
34	
35	    public function __construct(
36	        private readonly JwtTokenManager $jwtTokenManager,
37	        private readonly UserRepository $userRepository,
38	    ) {}
39	
40	    public function supports(Request $request): ?bool
41	    {
42	        $path = $request->getPathInfo();
43	
44	        // Public routes: explicitly skip authentication
45	        foreach (self::PUBLIC_ROUTES as $publicRoute) {
46	            if ($path === $publicRoute) {
47	                return false;
48	            }
49	        }
50	
51	        // Only authenticate /api/ routes
52	        return str_starts_with($path, '/api/');
53	    }
54	
55	    public function authenticate(Request $request): Passport
56	    {
57	        $authHeader = $request->headers->get('Authorization', '');
58	
59	        if (!str_starts_with($authHeader, 'Bearer ')) {
60	            throw new AuthenticationException('Missing or invalid Authorization header');
61	        }
62	
63	        $jwt = substr($authHeader, 7);
64	
65	        try {
66	            $claims = $this->jwtTokenManager->parseAccessToken($jwt);
67	        } catch (\Throwable) {
68	            throw new AuthenticationException('Invalid or expired token');
69	        }
70	
71	        $userId = $claims['user_id'] ?? null;
72	        if ($userId === null) {
73	            throw new AuthenticationException('Invalid token claims');
74	        }
75	
76	        return new SelfValidatingPassport(
77	            new UserBadge($userId, function (string $id) use ($claims) {
78	                $user = $this->userRepository->find($id);
79	
80	                if ($user === null || !$user->isActive() || $user->isFrozen()) {
81	                    throw new AuthenticationException(
82	                        $user !== null && $user->isFrozen()
83	                            ? 'Account is frozen'
84	                            : 'User not found or inactive'
85	                    );
86	                }
87	
88	                // Reject tokens issued before password change
89	                $tokenIssuedAt = $claims['issued_at'] ?? null;
90	                $passwordChangedAt = $user->getPasswordChangedAt();
91	                if ($tokenIssuedAt instanceof \DateTimeImmutable && $passwordChangedAt !== null) {
92	                    if ($tokenIssuedAt < $passwordChangedAt) {
93	                        throw new AuthenticationException('Token invalidated by password change');
94	                    }
95	                }
96	
97	                return $user;
98	            }),
99	        );
100	    }
101	
102	    public function onAuthenticationSuccess(Request $request, TokenInterface $token, string $firewallName): ?Response
103	    {
104	        // Set the authenticated user on the request for controller consumption.
105	        // This is the single source of truth — no supplemental listener needed.
106	        $user = $token->getUser();
107	        if ($user instanceof \App\Entity\User) {
108	            $request->attributes->set('authenticated_user', $user);
109	        }
110	        return null;
111	    }
112	
113	    public function onAuthenticationFailure(Request $request, AuthenticationException $exception): ?Response
114	    {
115	        return new JsonResponse([
116	            'code' => 401,
117	            'message' => $exception->getMessage(),
118	            'details' => null,
119	        ], 401);
120	    }
121	}
