5	namespace App\Service;
6	
7	use App\Audit\AuditActions;
8	use App\Entity\DeviceSession;
9	use App\Entity\Organization;
10	use App\Entity\Settings;
11	use App\Entity\User;
12	use App\Enum\UserRole;
13	use App\Exception\AccountFrozenException;
14	use App\Exception\AuthenticationException;
15	use App\Exception\BootstrapAlreadyCompletedException;
16	use App\Repository\DeviceSessionRepository;
17	use App\Repository\SettingsRepository;
18	use App\Repository\UserRepository;
19	use App\Security\JwtTokenManager;
20	use Doctrine\ORM\EntityManagerInterface;
21	use Symfony\Component\Uid\Uuid;
22	
23	class AuthService
24	{
25	    public function __construct(
26	        private readonly UserRepository $userRepository,
27	        private readonly DeviceSessionRepository $deviceSessionRepository,
28	        private readonly SettingsRepository $settingsRepository,
29	        private readonly JwtTokenManager $jwtTokenManager,
30	        private readonly AuditService $auditService,
31	        private readonly EntityManagerInterface $em,
32	    ) {}
33	
34	    public function authenticate(string $username, string $password, string $deviceLabel, string $clientDeviceId): array
35	    {
36	        $user = $this->userRepository->findByUsername($username);
37	
38	        if ($user === null || !password_verify($password, $user->getPasswordHash())) {
39	            throw new AuthenticationException('Invalid credentials');
40	        }
41	
42	        if ($user->isFrozen()) {
43	            throw new AccountFrozenException();
44	        }
45	
46	        if (!$user->isActive()) {
47	            throw new AuthenticationException('Account is inactive');
48	        }
49	
50	        $settings = $this->settingsRepository->findByOrganizationId($user->getOrganizationId());
51	        $maxDevices = min($settings !== null ? $settings->getMaxDevicesPerUser() : 5, 5);
52	
53	        $refreshToken = $this->jwtTokenManager->createRefreshToken();
54	        $refreshTokenHash = $this->jwtTokenManager->hashRefreshToken($refreshToken);
55	        $refreshTokenTtl = $this->jwtTokenManager->getRefreshTokenTtl();
56	        $expiresAt = new \DateTimeImmutable("+{$refreshTokenTtl} seconds");
57	
58	        // Atomic: revoke excess sessions + create new session in a single
59	        // transaction. Prevents a concurrent login from slipping in between
60	        // the revoke and the insert.
61	        $conn = $this->em->getConnection();
62	        $conn->beginTransaction();
63	        try {
64	            $this->deviceSessionRepository->revokeExcessByUserId($user->getId(), $maxDevices);
65	
66	            $session = new DeviceSession(
67	                Uuid::v4()->toRfc4122(),
68	                $user,
69	                $refreshTokenHash,
70	                $deviceLabel,
71	                $clientDeviceId,
72	                $expiresAt,
73	            );
74	
75	            $this->em->persist($session);
76	            $this->em->flush();
77	            $conn->commit();
78	        } catch (\Throwable $e) {
79	            if ($conn->isTransactionActive()) {
80	                $conn->rollBack();
81	            }
82	            throw $e;
83	        }
84	
85	        $accessToken = $this->jwtTokenManager->createAccessToken($user);
86	        $accessTokenTtl = $this->jwtTokenManager->getAccessTokenTtl();
87	
88	        $this->auditService->log(
89	            $user->getOrganizationId(),
90	            $user,
91	            $user->getUsername(),
92	            AuditActions::AUTH_LOGIN,
93	            'DeviceSession',
94	            $session->getId(),
95	            null,
96	            ['device_label' => $deviceLabel],
97	            $clientDeviceId,
98	        );
99	
100	        return [
101	            'access_token' => $accessToken,
102	            'refresh_token' => $refreshToken,
103	            'expires_in' => $accessTokenTtl,
104	            'session_id' => $session->getId(),
105	            'user' => $user,
106	        ];
107	    }
108	
109	    public function refreshToken(string $refreshTokenValue): array
110	    {
111	        $hash = $this->jwtTokenManager->hashRefreshToken($refreshTokenValue);
112	        $session = $this->deviceSessionRepository->findByRefreshTokenHash($hash);
113	
114	        if ($session === null) {
115	            throw new AuthenticationException('Invalid refresh token');
116	        }
117	
118	        if ($session->isRevoked()) {
119	            throw new AuthenticationException('Refresh token has been revoked');
120	        }
121	
122	        if ($session->isExpired()) {
123	            throw new AuthenticationException('Refresh token has expired');
124	        }
125	
126	        $session->updateLastSeen();
127	        $this->em->flush();
128	
129	        $user = $session->getUser();
130	        $accessToken = $this->jwtTokenManager->createAccessToken($user);
131	        $accessTokenTtl = $this->jwtTokenManager->getAccessTokenTtl();
132	
133	        return [
134	            'access_token' => $accessToken,
135	            'refresh_token' => $refreshTokenValue,
136	            'expires_in' => $accessTokenTtl,
137	            'user' => $user,
138	        ];
139	    }
140	
141	    public function logout(User $user, string $sessionId): void
142	    {
143	        $session = $this->deviceSessionRepository->find($sessionId);
144	
145	        if ($session === null) {
146	            throw new \App\Exception\EntityNotFoundException('DeviceSession', $sessionId);
147	        }
148	
149	        if ($session->getUserId() !== $user->getId()) {
150	            throw new \App\Exception\AccessDeniedException('Session does not belong to user');
151	        }
152	
153	        $session->revoke();
154	        $this->em->flush();
155	
156	        $this->auditService->log(
157	            $user->getOrganizationId(),
158	            $user,
159	            $user->getUsername(),
160	            AuditActions::AUTH_LOGOUT,
161	            'DeviceSession',
162	            $sessionId,
163	        );
164	    }
165	
166	    public function logoutAllSessions(User $user): void
167	    {
168	        $this->deviceSessionRepository->revokeAllByUserId($user->getId());
169	
170	        $this->auditService->log(
171	            $user->getOrganizationId(),
172	            $user,
173	            $user->getUsername(),
174	            AuditActions::AUTH_LOGOUT,
175	            'User',
176	            $user->getId(),
177	            null,
178	            ['scope' => 'all_sessions'],
179	        );
180	    }
181	
182	    public function changePassword(User $user, string $currentPassword, string $newPassword): void
183	    {
184	        if (!password_verify($currentPassword, $user->getPasswordHash())) {
185	            throw new AuthenticationException('Current password is incorrect');
186	        }
187	
188	        $user->setPasswordHash(password_hash($newPassword, PASSWORD_BCRYPT));
189	        $this->em->flush();
190	
191	        $this->deviceSessionRepository->revokeAllByUserId($user->getId());
192	
193	        $this->auditService->log(
194	            $user->getOrganizationId(),
195	            $user,
196	            $user->getUsername(),
197	            AuditActions::AUTH_PASSWORD_CHANGE,
198	            'User',
199	            $user->getId(),
200	        );
201	    }
202	
203	    public function bootstrap(
204	        string $orgName,
205	        string $orgCode,
206	        string $adminUsername,
207	        string $adminPassword,
208	        string $adminDisplayName,
209	        string $defaultCurrency = 'USD',
210	    ): array {
211	        $adminCount = $this->userRepository->countAdminsInSystem();
212	
213	        if ($adminCount > 0) {
214	            throw new BootstrapAlreadyCompletedException();
215	        }
216	
217	        $this->em->beginTransaction();
218	
219	        try {
220	            $orgId = Uuid::v4()->toRfc4122();
221	            $org = new Organization($orgId, $orgCode, $orgName);
222	            $org->setDefaultCurrency(strtoupper($defaultCurrency));
223	            $this->em->persist($org);
224	
225	            $settingsId = Uuid::v4()->toRfc4122();
226	            $settings = new Settings($settingsId, $org);
227	            $this->em->persist($settings);
228	
229	            $userId = Uuid::v4()->toRfc4122();
230	            $passwordHash = password_hash($adminPassword, PASSWORD_BCRYPT);
231	            $user = new User(
232	                $userId,
233	                $org,
234	                $adminUsername,
235	                $passwordHash,
236	                $adminDisplayName,
237	                UserRole::ADMINISTRATOR,
238	            );
239	            $this->em->persist($user);
240	
241	            $this->em->flush();
242	            $this->em->commit();
243	        } catch (\Throwable $e) {
244	            $this->em->rollback();
245	            throw $e;
246	        }
247	
248	        $this->auditService->log(
249	            $org->getId(),
250	            $user,
251	            $user->getUsername(),
252	            AuditActions::AUTH_BOOTSTRAP,
253	            'Organization',
254	            $org->getId(),
255	            null,
256	            ['org_name' => $orgName, 'org_code' => $orgCode, 'admin_username' => $adminUsername],
257	        );
258	
259	        return [
260	            'organization' => $org,
261	            'user' => $user,
262	        ];
263	    }
264	}
