5	namespace App\Repository;
6	
7	use App\Entity\DeviceSession;
8	use Doctrine\Bundle\DoctrineBundle\Repository\ServiceEntityRepository;
9	use Doctrine\Persistence\ManagerRegistry;
10	
11	/**
12	 * @extends ServiceEntityRepository<DeviceSession>
13	 */
14	class DeviceSessionRepository extends ServiceEntityRepository
15	{
16	    public function __construct(ManagerRegistry $registry)
17	    {
18	        parent::__construct($registry, DeviceSession::class);
19	    }
20	
21	    /**
22	     * @return DeviceSession[]
23	     */
24	    public function findActiveByUserId(string $userId): array
25	    {
26	        return $this->createQueryBuilder('ds')
27	            ->where('ds.user = :userId')
28	            ->andWhere('ds.revokedAt IS NULL')
29	            ->andWhere('ds.expiresAt > :now')
30	            ->setParameter('userId', $userId)
31	            ->setParameter('now', new \DateTimeImmutable())
32	            ->getQuery()
33	            ->getResult();
34	    }
35	
36	    public function countActiveByUserId(string $userId): int
37	    {
38	        return (int) $this->createQueryBuilder('ds')
39	            ->select('COUNT(ds.id)')
40	            ->where('ds.user = :userId')
41	            ->andWhere('ds.revokedAt IS NULL')
42	            ->andWhere('ds.expiresAt > :now')
43	            ->setParameter('userId', $userId)
44	            ->setParameter('now', new \DateTimeImmutable())
45	            ->getQuery()
46	            ->getSingleScalarResult();
47	    }
48	
49	    public function findOldestActiveByUserId(string $userId): ?DeviceSession
50	    {
51	        return $this->createQueryBuilder('ds')
52	            ->where('ds.user = :userId')
53	            ->andWhere('ds.revokedAt IS NULL')
54	            ->andWhere('ds.expiresAt > :now')
55	            ->setParameter('userId', $userId)
56	            ->setParameter('now', new \DateTimeImmutable())
57	            ->orderBy('ds.issuedAt', 'ASC')
58	            ->setMaxResults(1)
59	            ->getQuery()
60	            ->getOneOrNullResult();
61	    }
62	
63	    public function revokeAllByUserId(string $userId): int
64	    {
65	        return (int) $this->createQueryBuilder('ds')
66	            ->update()
67	            ->set('ds.revokedAt', ':now')
68	            ->where('ds.user = :userId')
69	            ->andWhere('ds.revokedAt IS NULL')
70	            ->setParameter('userId', $userId)
71	            ->setParameter('now', new \DateTimeImmutable())
72	            ->getQuery()
73	            ->execute();
74	    }
75	
76	    /**
77	     * Revoke the oldest active sessions to bring the count below the given cap.
78	     * Returns the number of sessions revoked.
79	     */
80	    public function revokeExcessByUserId(string $userId, int $maxAllowed): int
81	    {
82	        $active = $this->createQueryBuilder('ds')
83	            ->where('ds.user = :userId')
84	            ->andWhere('ds.revokedAt IS NULL')
85	            ->andWhere('ds.expiresAt > :now')
86	            ->setParameter('userId', $userId)
87	            ->setParameter('now', new \DateTimeImmutable())
88	            ->orderBy('ds.issuedAt', 'ASC')
89	            ->getQuery()
90	            ->getResult();
91	
92	        $excess = count($active) - $maxAllowed + 1; // +1 to make room for the new session
93	        if ($excess <= 0) {
94	            return 0;
95	        }
96	
97	        $revoked = 0;
98	        for ($i = 0; $i < $excess; $i++) {
99	            $active[$i]->revoke();
100	            $revoked++;
101	        }
102	
103	        return $revoked;
104	    }
105	
106	    public function findByRefreshTokenHash(string $hash): ?DeviceSession
107	    {
108	        return $this->findOneBy(['refreshTokenHash' => $hash]);
109	    }
110	}
