239	    public function restore(User $admin, string $filename): array
240	    {
241	        $this->rbac->enforce($admin, RbacEnforcer::ACTION_MANAGE_BACKUPS);
242	        $orgId = $this->orgScope->getOrganizationId($admin);
243	
244	        $filepath = $this->resolveBackupPath($filename, $orgId);
245	
246	        $encrypted = file_get_contents($filepath);
247	        if ($encrypted === false) {
248	            throw new EntityNotFoundException('Backup', $filename);
249	        }
250	
251	        $data = $this->decryptAndDecode($encrypted);
252	
253	        if ($data['metadata']['organization_id'] !== $orgId) {
254	            throw new AccessDeniedException();
255	        }
256	
257	        // Validate that all tables in the backup are on the allow-list.
258	        $invalidTables = array_diff(array_keys($data['data']), self::ORGANISATION_TABLES);
259	        if (!empty($invalidTables)) {
260	            throw new \RuntimeException('Backup contains unexpected tables: ' . implode(', ', $invalidTables));
261	        }
262	
263	        $connection = $this->em->getConnection();
264	        $restoredCounts = [];
265	
266	        $connection->beginTransaction();
267	        try {
268	            // Disable FK checks so delete/insert order doesn't matter.
269	            $connection->executeStatement('SET FOREIGN_KEY_CHECKS = 0');
270	
271	            foreach ($data['data'] as $table => $rows) {
272	                $connection->executeStatement(
273	                    sprintf('DELETE FROM %s WHERE organization_id = :orgId', $connection->quoteIdentifier($table)),
274	                    ['orgId' => $orgId],
275	                );
276	
277	                foreach ($rows as $row) {
278	                    $connection->insert($table, $row);
279	                }
280	
281	                $restoredCounts[$table] = count($rows);
282	            }
283	
284	            // Re-enable FK checks before validating integrity.
285	            $connection->executeStatement('SET FOREIGN_KEY_CHECKS = 1');
286	
287	            // Validate that all FK relationships are intact.
288	            $violations = $this->validateForeignKeyIntegrity($connection, $orgId, array_keys($data['data']));
289	            if (!empty($violations)) {
290	                throw new \RuntimeException(
291	                    'Restore aborted — FK integrity violations detected: ' . implode('; ', $violations)
292	                );
293	            }
294	
295	            // Validate that all enum-backed columns contain valid values.
296	            $enumViolations = $this->validateEnumIntegrity($connection, $orgId, array_keys($data['data']));
297	            if (!empty($enumViolations)) {
298	                throw new \RuntimeException(
299	                    'Restore aborted — invalid enum values detected: ' . implode('; ', $enumViolations)
300	                );
301	            }
302	
303	            $connection->commit();
304	        } catch (\Throwable $e) {
305	            // Ensure FK checks are re-enabled even on rollback.
306	            try {
307	                $connection->executeStatement('SET FOREIGN_KEY_CHECKS = 1');
308	            } catch (\Throwable) {
309	                // Best-effort; the connection may already be broken.
310	            }
311	            $connection->rollBack();
312	            throw $e;
313	        }
314	
315	        $this->auditService->log(
316	            $orgId,
317	            $admin,
318	            $admin->getUsername(),
319	            'BACKUP_RESTORED',
320	            'Backup',
321	            $filename,
322	            null,
323	            ['filename' => $filename, 'restored_counts' => $restoredCounts],
324	        );
325	
326	        return [
327	            'filename' => $filename,
328	            'restored_at' => (new \DateTimeImmutable())->format(\DateTimeInterface::ATOM),
329	            'restored_counts' => $restoredCounts,
330	        ];
331	    }
