333	    /**
334	     * Check all FK relationships among restored tables.
335	     * Returns an array of human-readable violation descriptions (empty = all good).
336	     */
337	    private function validateForeignKeyIntegrity(Connection $connection, string $orgId, array $restoredTables): array
338	    {
339	        $violations = [];
340	
341	        foreach (self::FK_CONSTRAINTS as [$childTable, $childColumn, $parentTable]) {
342	            // Only validate constraints where the child table was part of the restore.
343	            if (!in_array($childTable, $restoredTables, true)) {
344	                continue;
345	            }
346	
347	            $sql = sprintf(
348	                'SELECT COUNT(*) FROM %s c LEFT JOIN %s p ON c.%s = p.id'
349	                . ' WHERE c.organization_id = :orgId AND c.%s IS NOT NULL AND p.id IS NULL',
350	                $connection->quoteIdentifier($childTable),
351	                $connection->quoteIdentifier($parentTable),
352	                $connection->quoteIdentifier($childColumn),
353	                $connection->quoteIdentifier($childColumn),
354	            );
355	
356	            $orphanCount = (int) $connection->fetchOne($sql, ['orgId' => $orgId]);
357	            if ($orphanCount > 0) {
358	                $violations[] = sprintf(
359	                    '%s.%s → %s: %d orphaned row(s)',
360	                    $childTable,
361	                    $childColumn,
362	                    $parentTable,
363	                    $orphanCount,
364	                );
365	            }
366	        }
367	
368	        return $violations;
369	    }
370	
371	    /**
372	     * Validate that all enum-backed columns contain values from the allowed set.
373	     * Returns an array of human-readable violation descriptions (empty = all good).
374	     */
375	    private function validateEnumIntegrity(Connection $connection, string $orgId, array $restoredTables): array
376	    {
377	        $violations = [];
378	
379	        foreach (self::ENUM_CONSTRAINTS as [$table, $column, $allowedValues]) {
380	            if (!in_array($table, $restoredTables, true)) {
381	                continue;
382	            }
383	
384	            $placeholders = implode(',', array_map(fn ($v) => $connection->quote($v), $allowedValues));
385	            $sql = sprintf(
386	                'SELECT COUNT(*) FROM %s WHERE organization_id = :orgId AND %s NOT IN (%s)',
387	                $connection->quoteIdentifier($table),
388	                $connection->quoteIdentifier($column),
389	                $placeholders,
390	            );
391	
392	            $invalidCount = (int) $connection->fetchOne($sql, ['orgId' => $orgId]);
393	            if ($invalidCount > 0) {
394	                $violations[] = sprintf(
395	                    '%s.%s: %d row(s) with invalid enum value (allowed: %s)',
396	                    $table,
397	                    $column,
398	                    $invalidCount,
399	                    implode(', ', $allowedValues),
400	                );
401	            }
402	        }
403	
404	        return $violations;
405	    }
