407	    /**
408	     * Resolve a backup filename to a full path, preventing path traversal attacks.
409	     * Only allows filenames matching the pattern: backup_{orgId}_{timestamp}.enc
410	     */
411	    private function resolveBackupPath(string $filename, string $orgId): string
412	    {
413	        // Strip any directory components — only a bare filename is allowed.
414	        $safe = basename($filename);
415	
416	        // Enforce expected filename format to prevent arbitrary file access.
417	        if (!preg_match('/^backup_[a-zA-Z0-9\-]+_\d{8}_\d{6}\.enc$/', $safe)) {
418	            throw new \InvalidArgumentException('Invalid backup filename format');
419	        }
420	
421	        $filepath = rtrim($this->backupStoragePath, '/') . '/' . $safe;
422	
423	        if (!file_exists($filepath)) {
424	            throw new EntityNotFoundException('Backup', $safe);
425	        }
426	
427	        // Confirm the resolved path is still inside the storage directory (realpath check).
428	        $realStorage = realpath($this->backupStoragePath);
429	        $realFile = realpath($filepath);
430	        if ($realStorage === false || $realFile === false || !str_starts_with($realFile, $realStorage . DIRECTORY_SEPARATOR)) {
431	            throw new \InvalidArgumentException('Backup file path is outside storage directory');
432	        }
433	
434	        return $filepath;
435	    }
436	
437	    private function decryptAndDecode(string $encoded): array
438	    {
439	        $json = $this->decrypt($encoded);
440	        return json_decode($json, true, 512, JSON_THROW_ON_ERROR);
441	    }
442	
443	    private function encrypt(string $plaintext): string
444	    {
445	        $ivLength = openssl_cipher_iv_length(self::CIPHER);
446	        if ($ivLength === false) {
447	            throw new \RuntimeException('Failed to determine IV length for cipher');
448	        }
449	
450	        $iv = openssl_random_pseudo_bytes($ivLength);
451	        $ciphertext = openssl_encrypt($plaintext, self::CIPHER, $this->backupEncryptionKey, OPENSSL_RAW_DATA, $iv);
452	
453	        if ($ciphertext === false) {
454	            throw new \RuntimeException('Encryption failed');
455	        }
456	
457	        $hmac = hash_hmac('sha256', $iv . $ciphertext, $this->backupEncryptionKey, true);
458	
459	        return base64_encode($hmac . $iv . $ciphertext);
460	    }
461	
462	    private function decrypt(string $encoded): string
463	    {
464	        $raw = base64_decode($encoded, true);
465	        if ($raw === false) {
466	            throw new \RuntimeException('Invalid backup file encoding');
467	        }
468	
469	        $hmacLength = 32; // SHA-256 = 32 bytes
470	        $ivLength = openssl_cipher_iv_length(self::CIPHER);
471	        if ($ivLength === false) {
472	            throw new \RuntimeException('Failed to determine IV length for cipher');
473	        }
474	
475	        if (strlen($raw) < $hmacLength + $ivLength) {
476	            throw new \RuntimeException('Backup file is too short — likely corrupted');
477	        }
478	
479	        $hmac = substr($raw, 0, $hmacLength);
480	        $iv = substr($raw, $hmacLength, $ivLength);
481	        $ciphertext = substr($raw, $hmacLength + $ivLength);
482	
483	        // Verify integrity before decrypting (timing-safe comparison).
484	        $expectedHmac = hash_hmac('sha256', $iv . $ciphertext, $this->backupEncryptionKey, true);
485	        if (!hash_equals($expectedHmac, $hmac)) {
486	            throw new \RuntimeException('Backup integrity check failed — invalid key or corrupted data');
487	        }
488	
489	        $plaintext = openssl_decrypt($ciphertext, self::CIPHER, $this->backupEncryptionKey, OPENSSL_RAW_DATA, $iv);
490	
491	        if ($plaintext === false) {
492	            throw new \RuntimeException('Decryption failed');
493	        }
494	
495	        return $plaintext;
496	    }
497	}
