1	import { useState, useEffect, useRef, useMemo } from 'react';
2	
3	interface HoldTimerResult {
4	  remainingSeconds: number;
5	  isExpired: boolean;
6	  formatted: string;
7	}
8	
9	export function useHoldTimer(expiresAt: string | null | undefined): HoldTimerResult {
10	  const calcRemaining = (): number => {
11	    if (!expiresAt) return 0;
12	    const diff = Math.floor(
13	      (new Date(expiresAt).getTime() - Date.now()) / 1000,
14	    );
15	    return Math.max(0, diff);
16	  };
17	
18	  const [remainingSeconds, setRemainingSeconds] = useState(calcRemaining);
19	  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
20	
21	  useEffect(() => {
22	    setRemainingSeconds(calcRemaining());
23	
24	    if (intervalRef.current) {
25	      clearInterval(intervalRef.current);
26	    }
27	
28	    if (!expiresAt) return;
29	
30	    intervalRef.current = setInterval(() => {
31	      const r = calcRemaining();
32	      setRemainingSeconds(r);
33	      if (r <= 0 && intervalRef.current) {
34	        clearInterval(intervalRef.current);
35	        intervalRef.current = null;
36	      }
37	    }, 1000);
38	
39	    return () => {
40	      if (intervalRef.current) {
41	        clearInterval(intervalRef.current);
42	        intervalRef.current = null;
43	      }
44	    };
45	    // eslint-disable-next-line react-hooks/exhaustive-deps
46	  }, [expiresAt]);
47	
48	  const isExpired = remainingSeconds <= 0;
49	
50	  const formatted = useMemo(() => {
51	    const m = Math.floor(remainingSeconds / 60);
52	    const s = remainingSeconds % 60;
53	    return `${m}:${s.toString().padStart(2, '0')}`;
54	  }, [remainingSeconds]);
55	
56	  return { remainingSeconds, isExpired, formatted };
57	}
