        ['ledger_entries', 'refund_id', 'refunds'],
        ['notifications', 'user_id', 'users'],
        ['terminal_package_transfers', 'terminal_id', 'terminals'],
        ['audit_logs', 'actor_user_id', 'users'],
    ];

