16	export const useAuthStore = create<AuthState>((set) => {
17	  const storedUser = localStorage.getItem('user');
18	  const storedAccessToken = localStorage.getItem('access_token');
19	  const storedRefreshToken = localStorage.getItem('refresh_token');
20	  const storedSessionId = localStorage.getItem('session_id');
