26	    sessionId: storedSessionId,
27	    isAuthenticated: !!storedAccessToken,
28	
29	    setAuth: (response: AuthTokenResponse) => {
30	      localStorage.setItem('user', JSON.stringify(response.user));
31	      localStorage.setItem('access_token', response.access_token);
32	      localStorage.setItem('refresh_token', response.refresh_token);
33	      localStorage.setItem('session_id', response.session_id);
34	      set({
35	        user: response.user,
36	        accessToken: response.access_token,
37	        refreshToken: response.refresh_token,
38	        sessionId: response.session_id,
39	        isAuthenticated: true,
40	      });
41	    },
42	
43	    clearAuth: () => {
44	      localStorage.removeItem('user');
45	      localStorage.removeItem('access_token');
46	      localStorage.removeItem('refresh_token');
47	      localStorage.removeItem('session_id');
48	      set({
49	        user: null,
50	        accessToken: null,
51	        refreshToken: null,
52	        sessionId: null,
53	        isAuthenticated: false,
54	      });
55	    },
56	
57	    updateUser: (user: User) => {
58	      localStorage.setItem('user', JSON.stringify(user));
59	      set({ user });
60	    },
61	  };
62	});
63	
64	export function getUserRole(): UserRole | null {
65	  const state = useAuthStore.getState();
66	  return state.user?.role ?? null;
