    </MemoryRouter>,
  );
}

describe('CreateBookingPage', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  // ═══════════════════════════════════════════════════════════════
  // 1. Hold timer countdown display
  // ═══════════════════════════════════════════════════════════════

  it('displays hold timer after creating hold', async () => {
    vi.useRealTimers(); // Need real timers for async operations

    (inventoryApi.checkAvailability as any).mockResolvedValue({
      available_units: 5,
      requested_units: 1,
      total_capacity: 10,
      can_reserve: true,
    });

    const futureExpiry = new Date(Date.now() + 10 * 60 * 1000).toISOString();
    (bookingsApi.createHold as any).mockResolvedValue({
      id: 'hold-1',
      expires_at: futureExpiry,
      status: 'active',
    });

    renderPage();

    // Fill in search form
    const itemInput = screen.getByLabelText('Inventory Item ID');
    fireEvent.change(itemInput, { target: { value: 'item-1' } });

    const startInput = screen.getByLabelText('Start');
    fireEvent.change(startInput, { target: { value: '2026-04-15T10:00' } });

    const endInput = screen.getByLabelText('End');
    fireEvent.change(endInput, { target: { value: '2026-04-16T10:00' } });

    // Wait for availability check
    await waitFor(() => {
      expect(screen.getByText(/units available/i)).toBeInTheDocument();
    }, { timeout: 3000 });

    // Click reserve button
    const reserveBtn = screen.getByText(/Reserve 1 unit/);
    fireEvent.click(reserveBtn);

    // Wait for hold creation
    await waitFor(() => {
      expect(screen.getByText(/Hold Timer/i)).toBeInTheDocument();
    }, { timeout: 3000 });

    // Timer should show a time value (MM:SS format)
    expect(screen.getByText(/\d+:\d{2}/)).toBeInTheDocument();
  });

  // ═══════════════════════════════════════════════════════════════
  // 2. Booking policy / cancellation rules display
  // ═══════════════════════════════════════════════════════════════

  it('displays booking policy with cancellation rules in hold step', async () => {
    vi.useRealTimers();

    (inventoryApi.checkAvailability as any).mockResolvedValue({
      available_units: 5,
      requested_units: 1,
      total_capacity: 10,
      can_reserve: true,
    });

    const futureExpiry = new Date(Date.now() + 10 * 60 * 1000).toISOString();
    (bookingsApi.createHold as any).mockResolvedValue({
      id: 'hold-1',
      expires_at: futureExpiry,
      status: 'active',
    });

    renderPage();

    // Navigate to hold step
    fireEvent.change(screen.getByLabelText('Inventory Item ID'), { target: { value: 'item-1' } });
    fireEvent.change(screen.getByLabelText('Start'), { target: { value: '2026-04-15T10:00' } });
    fireEvent.change(screen.getByLabelText('End'), { target: { value: '2026-04-16T10:00' } });

    await waitFor(() => {
      expect(screen.getByText(/units available/i)).toBeInTheDocument();
    }, { timeout: 3000 });

    fireEvent.click(screen.getByText(/Reserve 1 unit/));

    await waitFor(() => {
      expect(screen.getByText('Booking Policy:')).toBeInTheDocument();
    }, { timeout: 3000 });

    // Verify all three cancellation/penalty rules are displayed
    expect(screen.getByText(/Free cancellation up to 24 hours/i)).toBeInTheDocument();
    expect(screen.getByText(/Late cancellation: 20% fee applies/i)).toBeInTheDocument();
    expect(screen.getByText(/No-show penalty: 50% \+ first day rent/i)).toBeInTheDocument();
    expect(screen.getByText(/By confirming, you acknowledge these terms/i)).toBeInTheDocument();
  });

  // ═══════════════════════════════════════════════════════════════
  // 3. Hold expiry disables confirmation
  // ═══════════════════════════════════════════════════════════════

  it('disables confirm button when hold is expired', async () => {
    vi.useRealTimers();

    (inventoryApi.checkAvailability as any).mockResolvedValue({
      available_units: 5,
      requested_units: 1,
      total_capacity: 10,
      can_reserve: true,
    });

    // Hold that's already expired
    const pastExpiry = new Date(Date.now() - 1000).toISOString();
    (bookingsApi.createHold as any).mockResolvedValue({
      id: 'hold-1',
      expires_at: pastExpiry,
      status: 'active',
    });

    renderPage();

    fireEvent.change(screen.getByLabelText('Inventory Item ID'), { target: { value: 'item-1' } });
    fireEvent.change(screen.getByLabelText('Start'), { target: { value: '2026-04-15T10:00' } });
    fireEvent.change(screen.getByLabelText('End'), { target: { value: '2026-04-16T10:00' } });

    await waitFor(() => {
      expect(screen.getByText(/units available/i)).toBeInTheDocument();
    }, { timeout: 3000 });

    fireEvent.click(screen.getByText(/Reserve 1 unit/));

    await waitFor(() => {
      expect(screen.getByText('Hold Expired')).toBeInTheDocument();
    }, { timeout: 3000 });

    // Button should be disabled
    const confirmBtn = screen.getByText('Hold Expired');
    expect(confirmBtn).toBeDisabled();
  });
});
