                $userId,
                $org,
                $adminUsername,
                $passwordHash,
                $adminDisplayName,
                UserRole::ADMINISTRATOR,
            );
            $this->em->persist($user);

            $this->em->flush();
            $this->em->commit();
        } catch (BootstrapAlreadyCompletedException $e) {
            throw $e;
        } catch (\Throwable $e) {
            if ($this->em->getConnection()->isTransactionActive()) {
