5	namespace App\Security;
6	
7	use Psr\Log\LoggerInterface;
8	use Symfony\Component\EventDispatcher\Attribute\AsEventListener;
9	use Symfony\Component\HttpFoundation\JsonResponse;
10	use Symfony\Component\HttpKernel\Event\ExceptionEvent;
11	use Symfony\Component\HttpKernel\KernelEvents;
12	
13	#[AsEventListener(event: KernelEvents::EXCEPTION, priority: 0)]
14	class ExceptionListener
15	{
16	    public function __construct(private readonly LoggerInterface $logger) {}
17	
18	    public function onKernelException(ExceptionEvent $event): void
19	    {
20	        $exception = $event->getThrowable();
21	
22	        if ($this->isAppException($exception)) {
23	            $statusCode = method_exists($exception, 'getHttpStatusCode')
24	                ? $exception->getHttpStatusCode()
25	                : 500;
26	
27	            $body = method_exists($exception, 'toArray')
28	                ? $exception->toArray()
29	                : [
30	                    'code' => $statusCode,
31	                    'message' => $exception->getMessage(),
32	                    'details' => null,
33	                ];
34	
35	            // Redact any UUIDs that may have leaked into the message field.
36	            $body['message'] = $this->redactSensitive($body['message']);
37	
38	            $event->setResponse(new JsonResponse($body, $statusCode));
39	            return;
40	        }
41	
42	        // DomainException → 409 Conflict (state machine violations, business rule violations)
43	        if ($exception instanceof \DomainException) {
44	            $event->setResponse(new JsonResponse([
45	                'code' => 409,
46	                'message' => $this->redactSensitive($exception->getMessage()),
47	                'details' => null,
48	            ], 409));
49	            return;
50	        }
51	
52	        // InvalidArgumentException → 422 Unprocessable Entity (validation failures)
53	        if ($exception instanceof \InvalidArgumentException) {
54	            $event->setResponse(new JsonResponse([
55	                'code' => 422,
56	                'message' => $this->redactSensitive($exception->getMessage()),
57	                'details' => null,
58	            ], 422));
59	            return;
60	        }
61	
62	        // Log redacted details internally — no raw IDs, no full stack traces.
63	        $this->logger->error('Unhandled exception', [
64	            'class'   => get_class($exception),
65	            'message' => $this->redactSensitive($exception->getMessage()),
66	            'file'    => basename($exception->getFile()) . ':' . $exception->getLine(),
67	        ]);
68	
69	        $event->setResponse(new JsonResponse([
70	            'code'    => 500,
71	            'message' => 'Internal server error',
72	            'details' => null,
73	        ], 500));
74	    }
75	
76	    private function isAppException(\Throwable $exception): bool
77	    {
78	        return str_starts_with(get_class($exception), 'App\\Exception\\');
79	    }
80	
81	    /**
82	     * Mask UUIDs and long hex strings in messages to prevent sensitive ID leakage.
83	     */
84	    public function redactSensitive(string $message): string
85	    {
86	        // Mask UUIDs: show only last 4 chars
87	        return preg_replace_callback(
88	            '/[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/i',
89	            fn(array $m) => '****' . substr($m[0], -4),
90	            $message,
91	        ) ?? $message;
92	    }
93	}
