452	                $excess = count($active) - $maxAllowed + 1;
453	                if ($excess <= 0) {
454	                    // Record count even when no revocation needed
455	                    $countAfterRevoke[] = count($active);
456	                    return 0;
457	                }
458	                for ($i = 0; $i < $excess; $i++) {
459	                    $this->sessionStore[$active[$i]['id']]['active'] = false;
460	                }
461	
462	                // Record the count AFTER revoke but BEFORE insert
463	                $countAfterRevoke[] = $this->countActive();
464	
465	                return $excess;
466	            });
