486	        $jwtManager->method('hashRefreshToken')->willReturn('h');
487	        $jwtManager->method('getRefreshTokenTtl')->willReturn(86400);
488	        $jwtManager->method('createAccessToken')->willReturn('at');
489	        $jwtManager->method('getAccessTokenTtl')->willReturn(900);
490	        $conn = $this->createMock(Connection::class);
491	        $em = $this->createMock(EntityManagerInterface::class);
492	        $em->method('getConnection')->willReturn($conn);
493	
494	        $authService = new AuthService(
495	            $userRepo, $deviceSessionRepo, $settingsRepo, $jwtManager,
496	            $this->createMock(AuditService::class), $em,
497	        );
498	
499	        // Run 8 logins starting at cap
500	        for ($i = 0; $i < 8; $i++) {
501	            $result = $authService->authenticate('testuser', 'pass', "dev-{$i}", "cli-{$i}");
502	            $this->sessionStore[$result['session_id']] = ['id' => $result['session_id'], 'active' => true];
503	        }
504	
505	        // The key assertion: after every revoke step (before insert),
506	        // the count must be at most (cap - 1) to leave room for the insert.
507	        foreach ($countAfterRevoke as $i => $count) {
508	            $this->assertLessThanOrEqual(
509	                self::MAX_DEVICES - 1,
510	                $count,
511	                "After revoke step #{$i}, count ({$count}) must be <= "
512	                . (self::MAX_DEVICES - 1) . " to leave room for the new session",
513	            );
514	        }
515	
516	        $this->assertCount(8, $countAfterRevoke, 'Must have recorded count for all 8 login attempts');
517	        $this->assertSame(self::MAX_DEVICES, $this->countActive());
518	    }
